import{_ as s,o as e,c as a,a2 as t}from"./chunks/framework.C69UpXSI.js";const k=JSON.parse('{"title":"MCP (Model Context Protocol)","description":"","frontmatter":{},"headers":[],"relativePath":"it/configurazione/mcp.md","filePath":"it/configurazione/mcp.md"}'),o={name:"it/configurazione/mcp.md"};function n(l,i,r,p,d,c){return e(),a("div",null,[...i[0]||(i[0]=[t(`<h1 id="mcp-model-context-protocol" tabindex="-1">MCP (Model Context Protocol) <a class="header-anchor" href="#mcp-model-context-protocol" aria-label="Permalink to &quot;MCP (Model Context Protocol)&quot;">​</a></h1><p>TurboDev supporta la connessione a server di strumenti esterni tramite il <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">Model Context Protocol</a> (MCP) — uno standard open adottato da Claude Code, VS Code Copilot, Cursor, ChatGPT e altri. Un singolo server MCP funziona su tutti questi tool, TurboDev incluso.</p><p><strong>Scope V1</strong>: solo transport stdio, solo primitiva tools, solo configurazione a livello progetto.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><p>Crea il file <code>.turbodev/mcp.json</code> nella root del progetto (formato compatibile con Claude Desktop):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;filesystem&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@modelcontextprotocol/server-filesystem&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/Users/me/projects&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Avvia TurboDev. Il server viene lanciato come processo figlio via stdio, viene eseguito l&#39;handshake MCP <code>initialize</code>, e ogni tool esposto dal server viene registrato con un nome prefissato (<code>mcp__&lt;server&gt;__&lt;tool&gt;</code>) così l&#39;LLM può invocarlo come un tool nativo.</p><p>Digita <code>/mcp</code> per verificare la connessione:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MCP Servers (1 connected, 5 tools total):</span></span>
<span class="line"><span>  ✓ filesystem            5 tools    connected</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Use /mcp reload to re-read .turbodev/mcp.json and reconnect.</span></span></code></pre></div><h2 id="riferimento-configurazione" tabindex="-1">Riferimento Configurazione <a class="header-anchor" href="#riferimento-configurazione" aria-label="Permalink to &quot;Riferimento Configurazione&quot;">​</a></h2><p>Il file di configurazione si trova in <code>&lt;project&gt;/.turbodev/mcp.json</code> e segue lo schema <code>mcpServers</code> di Claude Desktop byte-per-byte — puoi copiare configurazioni tra tool.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Tipo</th><th>Richiesto</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>command</code></td><td><code>string</code></td><td>sì</td><td>Eseguibile da lanciare (risolto via <code>PATH</code>, mai tramite shell).</td></tr><tr><td><code>args</code></td><td><code>string[]</code></td><td>no</td><td>Argomenti passati al comando.</td></tr><tr><td><code>env</code></td><td><code>Record&lt;string, string&gt;</code></td><td>no</td><td>Variabili d&#39;ambiente per il processo figlio. Supporta espansione <code>$VAR</code>, <code>\${VAR}</code>, e <code>~</code> iniziale.</td></tr></tbody></table><p>Esempio con tutti i campi:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;github&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@modelcontextprotocol/server-github&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;env&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;GITHUB_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$GITHUB_TOKEN&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;LOG_DIR&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~/logs/mcp&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>I campi sconosciuti in una voce server vengono ignorati (compatibilità forward). Le voci non valide vengono saltate con un warning nel log; le voci valide nello stesso file vengono comunque caricate.</p><h2 id="comandi" tabindex="-1">Comandi <a class="header-anchor" href="#comandi" aria-label="Permalink to &quot;Comandi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Comando</th><th>Descrizione</th></tr></thead><tbody><tr><td><code>/mcp</code></td><td>Elenca tutti i server con stato (<code>connected</code>/<code>error</code>/<code>disabled</code>), numero di tool e messaggi di errore.</td></tr><tr><td><code>/mcp reload</code></td><td>Rilegge <code>.turbodev/mcp.json</code>, disconnette i server rimossi/cambiati, connette quelli nuovi. I server invariati non vengono toccati (no churn).</td></tr></tbody></table><p>La status bar mostra <code>MCP:N</code> (magenta) quando ci sono N server connessi.</p><h2 id="permessi" tabindex="-1">Permessi <a class="header-anchor" href="#permessi" aria-label="Permalink to &quot;Permessi&quot;">​</a></h2><p>I tool MCP hanno default <strong><code>ask</code></strong> — l&#39;utente deve approvare la prima invocazione per ogni server. Override per-server in un file agent Markdown:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-agent</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">permission</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mcp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">filesystem</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">allow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">github</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p>Oppure globalmente per tutti i server MCP:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">permission</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mcp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">allow</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # autorizza ogni tool MCP senza chiedere</span></span></code></pre></div><p>Ordine di risoluzione: voce per-server → stringa globale → default <code>ask</code>. Disabilitare un tool specifico via <code>tools: { &quot;mcp__filesystem__read_file&quot;: false }</code> continua a funzionare e ha precedenza (ritorna <code>deny</code>).</p><h2 id="sicurezza" tabindex="-1">Sicurezza <a class="header-anchor" href="#sicurezza" aria-label="Permalink to &quot;Sicurezza&quot;">​</a></h2><ul><li><strong>Niente shell</strong>: <code>command</code>/<code>args</code> sono passati a <code>child_process.spawn</code> direttamente, mai tramite shell — nessuna injection possibile.</li><li><strong>Espansione env locale</strong>: <code>$VAR</code> e <code>~</code> vengono espansi da TurboDev prima dello spawn; il server riceve i valori già risolti.</li><li><strong>I segreti non vengono mai loggati</strong>: se una voce config non è valida, viene loggato solo il <em>nome</em> del server, mai command, args o valori env.</li><li><strong>Default <code>ask</code></strong>: i tool esterni non possono eseguire senza opt-in esplicito dell&#39;utente.</li></ul><h2 id="risoluzione-problemi" tabindex="-1">Risoluzione Problemi <a class="header-anchor" href="#risoluzione-problemi" aria-label="Permalink to &quot;Risoluzione Problemi&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sintomo</th><th>Causa / Fix</th></tr></thead><tbody><tr><td><code>✗ server error ENOENT</code></td><td>Il <code>command</code> non è trovato in <code>PATH</code>. Verifica che l&#39;eseguibile sia installato (es. <code>npx -y @modelcontextprotocol/server-filesystem --help</code> funziona fuori da TurboDev).</td></tr><tr><td><code>✗ server error MCP connect timeout (10s)</code></td><td>Il server è partito ma non risponde all&#39;handshake <code>initialize</code>. Controlla lo stderr del server nella console.</td></tr><tr><td>Il server sparisce da <code>/mcp</code> dopo reload</td><td>La voce è stata rimossa da <code>.turbodev/mcp.json</code> o ha fallito la validazione — controlla il warning nel log.</td></tr><tr><td>Permesso negato su ogni chiamata</td><td><code>permission.mcp</code> dell&#39;agent è impostato a <code>deny</code>, oppure il nome server in <code>permission.mcp</code> non matcha la chiave in <code>mcpServers</code>.</td></tr><tr><td>Il tool ritorna <code>Cancelled by user</code></td><td>Hai premuto Escape durante la chiamata. Ri-emetti la richiesta per riprovare.</td></tr></tbody></table><h2 id="limitazioni-v1" tabindex="-1">Limitazioni (V1) <a class="header-anchor" href="#limitazioni-v1" aria-label="Permalink to &quot;Limitazioni (V1)&quot;">​</a></h2><ul><li><strong>Solo transport stdio</strong> — niente server HTTP remoti (Phase 2)</li><li><strong>Solo primitiva tools</strong> — niente resources, prompts, sampling o elicitation (Phase 2/3)</li><li><strong>Solo config a livello progetto</strong> — niente <code>~/.config/turbodev/mcp.json</code> globale (Phase 2)</li><li><strong>Niente <code>notifications/tools/list_changed</code></strong> — usa <code>/mcp reload</code> per aggiornare i tool lato server</li><li><strong>Niente OAuth</strong> — solo auth basata su env var</li></ul><h2 id="scoprire-server" tabindex="-1">Scoprire Server <a class="header-anchor" href="#scoprire-server" aria-label="Permalink to &quot;Scoprire Server&quot;">​</a></h2><p>Sfoglia i server di riferimento ufficiali su <a href="https://github.com/modelcontextprotocol/servers" target="_blank" rel="noreferrer">github.com/modelcontextprotocol/servers</a> e il catalogo community su <a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">modelcontextprotocol.io</a>. Qualsiasi server basato su stdio che segue lo spec MCP funziona con TurboDev.</p>`,32)])])}const g=s(o,[["render",n]]);export{k as __pageData,g as default};
